# Check what vllm version requires vllm-flash-attn 2.6.1 or 2.6.2
python3 -c "
import urllib.request, json
# Check vllm 0.7.0 deps
resp = urllib.request.urlopen('https://pypi.org/pypi/vllm/0.7.0/json')
data = json.loads(resp.read())
deps = data['info']['requires_dist']
if deps:
    for d in deps:
        if 'flash' in d.lower():
            print('0.7.0:', d)
# Check vllm 0.7.1
resp2 = urllib.request.urlopen('https://pypi.org/pypi/vllm/0.7.1/json')
data2 = json.loads(resp2.read())
deps2 = data2['info']['requires_dist']
if deps2:
    for d in deps2:
        if 'flash' in d.lower():
            print('0.7.1:', d)
" 2>&1

# Check if vllm 0.8.x works with torch 2.6 cu124 and has flash_attn for cp312
# vllm-flash-attn 2.6.1 has cp312 wheels. Let's check what vllm version uses it
python3 -c "
import urllib.request, json

for v in ['0.7.0', '0.7.1', '0.7.2', '0.7.3']:
    try:
        resp = urllib.request.urlopen(f'https://pypi.org/pypi/vllm/{v}/json')
        data = json.loads(resp.read())
        deps = data['info']['requires_dist'] or []
        for d in deps:
            if 'flash' in d.lower() or 'torch' in d.lower():
                print(f'{v}: {d}')
    except Exception as e:
        print(f'{v}: error {e}')
" 2>&1

